// ==================== TypeScript Interfaces for Cold Logic ====================

/**
 * Cold Logic Checker - Scripts that can sit idle as checking mechanism
 * Checks down the chain for problems and recommends adjustments
 */
export interface ColdLogicChecker {
  id: string;
  name: string;
  description?: string;
  type: ColdLogicType;
  priority?: number;
  state?: ColdLogicState;
  triggerConfig: TriggerConfig;
  checkChain: CheckChain;
  adjustmentConfig: AdjustmentConfig;
  script?: CheckerScript;
  metrics?: CheckerMetrics;
  history?: CheckResult[];
  metadata?: ColdLogicMetadata;
}

export type ColdLogicType = 
  | 'performance' 
  | 'correctness' 
  | 'resource' 
  | 'compliance' 
  | 'security' 
  | 'quality' 
  | 'drift' 
  | 'anomaly' 
  | 'custom';

/**
 * Cold Logic State - can sit idle
 */
export interface ColdLogicState {
  status: 'idle' | 'checking' | 'reporting' | 'error' | 'disabled';
  idleTime?: number;
  lastCheckTime?: string;
  lastCheckDuration?: number;
  totalChecks?: number;
  errorCount?: number;
}

/**
 * Trigger Configuration
 */
export interface TriggerConfig {
  mode: 'continuous' | 'periodic' | 'event_driven' | 'on_demand' | 'chain_triggered';
  interval?: number;
  events?: TriggerEvent[];
  conditions?: TriggerCondition[];
  backoff?: BackoffConfig;
}

export type TriggerEvent = 
  | 'state_change' 
  | 'error' 
  | 'threshold_breach' 
  | 'chain_complete' 
  | 'adjustment_applied';

export interface TriggerCondition {
  metric: string;
  operator: '>' | '<' | '>=' | '<=' | '==' | '!=' | 'contains' | 'matches';
  value: unknown;
  logicalOperator?: 'and' | 'or' | 'not';
}

export interface BackoffConfig {
  enabled: boolean;
  initialDelay: number;
  maxDelay: number;
  multiplier: number;
}

/**
 * Check Chain - checks down the chain for problems
 */
export interface CheckChain {
  links: ChainLink[];
  executionMode: 'sequential' | 'parallel' | 'conditional';
  stopOnFailure?: boolean;
  rollbackOnFailure?: boolean;
}

export interface ChainLink {
  id: string;
  name: string;
  description?: string;
  order?: number;
  check: CheckDefinition;
  onSuccess?: string;
  onFailure?: string;
  dependencies?: string[];
  timeout?: number;
  retryCount?: number;
}

export interface CheckDefinition {
  type: 'metric' | 'state' | 'output' | 'resource' | 'custom';
  target?: string;
  operator?: CheckOperator;
  expectedValue?: unknown;
  tolerance?: number;
  script?: string;
  dataPath?: string;
  aggregation?: 'avg' | 'sum' | 'min' | 'max' | 'count' | 'none';
  windowSize?: number;
}

export type CheckOperator = 
  | '>' 
  | '<' 
  | '>=' 
  | '<=' 
  | '==' 
  | '!=' 
  | 'contains' 
  | 'matches' 
  | 'between' 
  | 'outside';

/**
 * Adjustment Configuration
 */
export interface AdjustmentConfig {
  autoApply?: boolean;
  requireApproval?: boolean;
  approvalChannel?: string;
  adjustmentTypes?: AdjustmentType[];
  maxAdjustments?: number;
  cooldownPeriod?: number;
  rollbackConfig?: RollbackConfig;
}

export type AdjustmentType = 
  | 'parameter_tune' 
  | 'resource_scale' 
  | 'state_change' 
  | 'model_switch' 
  | 'prompt_update' 
  | 'restart' 
  | 'migration'
  | 'config_update';

export interface RollbackConfig {
  enabled: boolean;
  maxSnapshots: number;
  autoRollback: boolean;
  rollbackThreshold?: number;
}

/**
 * Checker Script
 */
export interface CheckerScript {
  language: 'python' | 'javascript' | 'typescript' | 'bash' | 'wasm';
  source: 'inline' | 'file' | 'url' | 'module';
  code?: string;
  path?: string;
  url?: string;
  entrypoint?: string;
  dependencies?: string[];
  timeout?: number;
  sandboxConfig?: SandboxConfig;
}

export interface SandboxConfig {
  enabled: boolean;
  networkAccess: boolean;
  fileSystemAccess: boolean;
  maxMemory: number;
}

/**
 * Metrics Configuration
 */
export interface CheckerMetrics {
  metrics: MetricDefinition[];
  collectionInterval?: number;
  retentionPeriod?: number;
}

export interface MetricDefinition {
  name: string;
  type: 'gauge' | 'counter' | 'histogram' | 'summary';
  unit?: string;
  description?: string;
  labels?: string[];
}

/**
 * Check Result
 */
export interface CheckResult {
  timestamp: string;
  status: 'pass' | 'fail' | 'warning' | 'error' | 'skipped';
  checkId?: string;
  linkId?: string;
  message?: string;
  details?: Record<string, unknown>;
  recommendations?: AdjustmentRecommendation[];
  executionTime?: number;
  chainResults?: ChainLinkResult[];
}

export interface ChainLinkResult {
  linkId: string;
  status: 'pass' | 'fail' | 'warning' | 'error' | 'skipped';
  message?: string;
  actualValue?: unknown;
  expectedValue?: unknown;
  executionTime?: number;
}

/**
 * Adjustment Recommendation
 */
export interface AdjustmentRecommendation {
  id?: string;
  type: AdjustmentType;
  description: string;
  priority: 'low' | 'medium' | 'high' | 'critical';
  impact?: 'minor' | 'moderate' | 'major' | 'breaking';
  changes?: ChangeDefinition[];
  automated?: boolean;
  approvalRequired?: boolean;
  rollbackPlan?: string;
  estimatedDowntime?: number;
  riskLevel?: number;
}

export interface ChangeDefinition {
  path: string;
  current?: unknown;
  proposed: unknown;
  reason?: string;
}

/**
 * Metadata
 */
export interface ColdLogicMetadata {
  version?: string;
  author?: string;
  createdAt?: string;
  updatedAt?: string;
  tags?: string[];
  documentation?: string;
}

// ==================== Executor Interface ====================

/**
 * Cold Logic Executor - executes checks and manages state
 */
export interface ColdLogicExecutor {
  check(checker: ColdLogicChecker): Promise<CheckResult>;
  applyAdjustment(checker: ColdLogicChecker, recommendation: AdjustmentRecommendation): Promise<boolean>;
  rollback(checker: ColdLogicChecker, snapshotId: string): Promise<boolean>;
  getState(checker: ColdLogicChecker): ColdLogicState;
  setIdle(checker: ColdLogicChecker): void;
  wakeUp(checker: ColdLogicChecker): void;
}

/**
 * Factory for creating cold logic checkers
 */
export interface ColdLogicFactory {
  create(config: Partial<ColdLogicChecker>): ColdLogicChecker;
  fromTemplate(templateId: string, overrides?: Partial<ColdLogicChecker>): ColdLogicChecker;
  clone(sourceId: string, modifications?: Partial<ColdLogicChecker>): ColdLogicChecker;
}

